    for _, w := range t.words {
        if w == word {
            return true
        }
    }
    return false
}

func (t *Trie) startsWith(prefix string) bool {
    for _, w := range t.words {
        if len(w) >= len(prefix) && w[:len(prefix)] == prefix {
            return true
        }
    }
    return false
}

